module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

    reg [15:0] a_reg, b_reg;
    reg [31:0] p_reg;
    reg [4:0] count;
    reg done_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            a_reg <= 0;
            b_reg <= 0;
            p_reg <= 0;
            count <= 0;
            done_reg <= 0;
        end else if (start) begin
            if (count == 0) begin
                a_reg <= ain;
                b_reg <= bin;
                p_reg <= 0;
                count <= 16;
            end else if (count > 0) begin
                if (a_reg[0]) p_reg <= p_reg + b_reg;
                a_reg <= a_reg >> 1;
                b_reg <= b_reg << 1;
                count <= count - 1;
            end
            if (count == 1) done_reg <= 1;
            else if (count == 0) done_reg <= 0;
        end
    end

    assign yout = p_reg;
    assign done = done_reg;

endmodule
